import psycopg2
import os

def get_db_connection():
    try:
        connection = psycopg2.connect(
            host="localhost",
            port="5432",
            database=os.getenv('DB_NAME', 'hackathon_db'),
            user=os.getenv('DB_USER', 'admin'),
            password=os.getenv('DB_PASSWORD', 'demo123')
        )
        return connection
    except psycopg2.DatabaseError as error:
        print(f"Error: {error}")
        return None

